class Solution:
    def countStableSubsequences(self, nums):
        MOD = 10**9 + 7
        n = len(nums)
        cnt = 0
        for mask in range(1, 1 << n):
            sub = [nums[i] for i in range(n) if mask & (1 << i)]
            ok = True
            for i in range(2, len(sub)):
                if sub[i] % 2 == sub[i-1] % 2 == sub[i-2] % 2:
                    ok = False
                    break
            if ok:
                cnt += 1
        return cnt % MOD

