class Solution:
    def countStableSubsequences(self, nums):
        MOD = 10**9 + 7
        e1 = e2 = o1 = o2 = 0
        for x in nums:
            if x % 2 == 0:
                add2 = e1
                add1 = (o1 + o2 + 1) % MOD
                e2 = (e2 + add2) % MOD
                e1 = (e1 + add1) % MOD
            else:
                add2 = o1
                add1 = (e1 + e2 + 1) % MOD
                o2 = (o2 + add2) % MOD
                o1 = (o1 + add1) % MOD
        return (e1 + e2 + o1 + o2) % MOD

